import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    available_nodes = set(unvisited_nodes) - set(truck_nodes)
    if not available_nodes:
        return None

    min_distance = float('inf')
    next_node = None

    for node in available_nodes:
        if distance_matrix[current_node][node] < min_distance:
            min_distance = distance_matrix[current_node][node]
            next_node = node

    return next_node
